class Solution:
    def minChanges(self, nums: List[int], k: int) -> int:
        n = len(nums)
        res = float('inf')
        for mask in range(1 << k):
            cnt = 0
            for i in range(n):
                if (mask >> (i % k)) & 1 != nums[i]:
                    cnt += 1
            res = min(res, cnt)
        return res
